// Qoka brand assets embedded as data URIs so the workbench can render them
// without a bundled-media round-trip (FileAccess svg/png isn't packaged for
// these contribs). QOKA_MARK = the standalone quokka mark (reads
// on both light and dark backgrounds). QOKA_LOGO = mark + 'qoka' wordmark
// (black lettering - light backgrounds only).

export const ARIA_MARK = 'data:image/png;base64,';
export const ARIA_LOGO = 'data:image/png;base64,';
